/**
 * Service-layer orchestration for account dashboard data.
 *
 * @accountId Account identifier.
 * @return struct
 */
public struct function buildDashboard(required numeric accountId) {
  var users = variables.userRepository.getByAccount(arguments.accountId);
  var orders = variables.orderRepository.getByAccount(arguments.accountId);
  return {
    userCount: users.recordCount,
    orderCount: orders.recordCount,
    users: users,
    orders: orders
  };
}

/**
 * User service with explicit injected dependencies.
 */
component accessors='false' {

  /**
   * Injected user repository dependency.
   */
  property name='userRepository' inject='UserRepository';

  /**
   * Returns active user DTOs for account context.
   *
   * @accountId Account identifier.
   * @return array
   */
  public array function getActiveUsers(required numeric accountId) {
    var rows = variables.userRepository.getByAccount(arguments.accountId);
    return rows.filter(function(required struct row) { return row.status == 'active'; });
  }
}

/**
 * Returns a controller-ready sales report model.
 *
 * @accountId Account identifier.
 * @return struct
 */
public struct function generateSalesReport(required numeric accountId) {
  var totals = variables.salesRepository.getTotals(arguments.accountId);
  var trends = variables.salesRepository.getTrend(arguments.accountId);
  return {
    totals: totals,
    trends: trends,
    generatedAt: now()
  };
}

