/**
 * Isolated service method for subscription renewal policy decisions.
 *
 * @subscription Subscription model.
 * @return struct
 */
public struct function evaluateRenewal(required struct subscription) {
  var isRenewable = subscription.status == 'active' && dateDiff('d', now(), subscription.expiresOn) <= 30;
  return {
    renewable: isRenewable,
    reason: isRenewable ? 'within-renewal-window' : 'outside-window-or-inactive'
  };
}

/**
 * Centralizes order approval rules used by multiple controllers.
 *
 * @order Order model.
 * @actor User performing action.
 * @return boolean
 */
public boolean function canApproveOrder(required struct order, required struct actor) {
  if (actor.role == 'admin') {
    return true;
  }
  return order.status == 'pending' && actor.id == order.ownerId;
}

/**
 * Registers a new user and returns a standardized response.
 *
 * @input struct   Registration fields.
 * @return struct
 */
public struct function register(required struct input) {
  var validation = variables.validator.validateRegistration(arguments.input);
  if (!validation.isValid) {
    return { success: false, errors: validation.errors, data: {} };
  }

  var userId = variables.userRepository.insertUser(arguments.input.email, arguments.input.displayName);
  variables.notificationService.dispatch('welcome', userId);

  return { success: true, errors: [], data: { userId: userId } };
}

