/**
 * Builds a complete user profile view model for the dashboard.
 *
 * @userId numeric   User identifier.
 * @return struct
 * @throws application When the user record is not found.
 */
public struct function buildDashboard(required numeric userId) {
  var user = variables.userRepository.findById(arguments.userId);
  if (isNull(user)) {
    throw(type='application', message='User not found.');
  }

  return {
    user: user,
    recentActivity: variables.activityRepository.getRecent(arguments.userId, 10),
    notifications: variables.notificationRepository.getUnread(arguments.userId)
  };
}

