/**
 * Processes a subscription upgrade atomically.
 *
 * @userId numeric      User identifier.
 * @planId numeric      New subscription plan identifier.
 * @return struct
 * @throws application When plan or billing update fails.
 */
public struct function upgradeSubscription(required numeric userId, required numeric planId) {
  transaction {
    try {
      variables.subscriptionRepository.update(arguments.userId, arguments.planId);
      variables.billingService.chargeUpgrade(arguments.userId, arguments.planId);
      variables.auditService.log('subscription_upgraded', arguments.userId);
    } catch (database dbEx) {
      throw(type='application', message='Subscription upgrade failed.', detail=dbEx.message);
    }
  }

  return { success: true, data: { planId: arguments.planId } };
}

/**
 * User management service with injected repository and notification dependencies.
 */
component singleton accessors='true' {
  property userRepository;
  property notificationService;

  /**
   * Deactivates a user account and sends a farewell notification.
   *
   * @userId numeric   User identifier.
   * @return void
   */
