/**
 * Marks a job as complete and dispatches a completion event.
 *
 * @jobId numeric   Job identifier.
 * @result struct   Completion metadata.
 * @return void
 * @throws application When state update or event dispatch fails.
 */
public void function completeJob(required numeric jobId, required struct result) {
  transaction {
    try {
      variables.jobRepository.setStatus(arguments.jobId, 'complete', arguments.result);
      variables.eventBus.dispatch('job.completed', { jobId: arguments.jobId, result: arguments.result });
    } catch (database dbEx) {
      throw(type='application', message='Job completion failed.', detail=dbEx.message);
    }
  }
}

/**
 * Returns only active, non-suspended members mapped to a summary struct.
 * Uses CF2025+ arrow function syntax for concise collection pipelines.
 *
 * @members array  Array of member structs with active, accountType, id, name fields.
 * @return  array  Filtered and mapped summary structs.
 */
public array function getActiveMemberSummaries(required array members) {
    // CF2025+: arrow functions — no 'function' keyword or return statement needed
    return arguments.members
        .filter(m => m.active && m.accountType != "suspended")
        .map(m => {
            return {
                id:          m.id,
                displayName: m.name,
                type:        m.accountType
            };
        });
}

