// CF10-safe fallback: traditional anonymous function syntax
public array function getActiveMemberSummaries(required array members) {
    var active = arguments.members.filter(function(m) {
        return m.active && m.accountType != 'suspended';
    });
    return active.map(function(m) {
        return { id: m.id, displayName: m.name, type: m.accountType };
    });
}
